<?php
namespace App\Domain\Characters\Appearance;use InvalidArgumentException;
final class CharacterVisualLayerOrder{const BASE_BODY='base_body';const PENDANT='pendant';const RING_LEFT='ring_left';const RING_RIGHT='ring_right';const HELMET='helmet';const GLOVES='gloves';const BOOTS='boots';const ARMOR='armor';const OFF_HAND='off_hand';const MAIN_HAND='main_hand';private const ORDERS=[self::BASE_BODY=>10,self::PENDANT=>20,self::RING_LEFT=>30,self::RING_RIGHT=>40,self::HELMET=>50,self::GLOVES=>60,self::BOOTS=>70,self::ARMOR=>80,self::OFF_HAND=>90,self::MAIN_HAND=>100];private const LABELS=[self::BASE_BODY=>'Cuerpo base',self::PENDANT=>'Pendiente',self::RING_LEFT=>'Anillo izquierdo',self::RING_RIGHT=>'Anillo derecho',self::HELMET=>'Casco',self::GLOVES=>'Guantes',self::BOOTS=>'Botas',self::ARMOR=>'Armadura',self::OFF_HAND=>'Mano secundaria',self::MAIN_HAND=>'Arma principal'];public static function orderedSlots(){return array_keys(self::ORDERS);}public static function supports($slot){return isset(self::ORDERS[$slot]);}public static function labels(){return self::LABELS;}public static function orderForSlot($slot){if(!self::supports($slot))throw new InvalidArgumentException('Canal visual no soportado.');return self::ORDERS[$slot];}private function __construct(){}}
